var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_A","text":{"KOREA":"크헉!? 컥......! 커헉......!","JPN":"ぐあっ！　くっ……！　ガハッ……！","ENG":"Ack!? Hngh! Aaah!","TWN":"呃！？咳……！咳……！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CRIMINAL_NPC_MEMBER_B","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_B","text":{"KOREA":"젠장! 그 후드 쓴 자식 어디로 숨은 거야!","JPN":"くそっ！　あのフード野郎はどこに隠れてるんだ？","ENG":"Darn it! Where did that hooded bastard go?","TWN":"該死！那個穿帽T的藏到哪裡了！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CRIMINAL_NPC_MEMBER_B","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_B","text":{"KOREA":"아무도 못 봤어?!","JPN":"誰も見てないのか！？","ENG":"Anyone seen him?!","TWN":"沒人看見嗎？！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CRIMINAL_NPC_MEMBER_B","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_B","text":{"KOREA":"끄아아아악!! 내 팔......! 내 팔이이이!","JPN":"ぐああああ！　俺の腕が……！　腕があああ！","ENG":"Aaack! My arm! My arrrm!","TWN":"啊啊啊啊啊！！手臂……！我的手臂！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"총 쏘는 법 하나는 제대로 배웠군.","JPN":"銃の撃ち方だけは熟知しているようだな。","ENG":"I've got to give it to you boy, you sure learned to shoot well.","TWN":"你的射擊術練得不錯。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"그걸로 하는 일이 인간백정 노릇이라는 게 안타깝지만.","JPN":"それでやってる仕事が殺し屋ってことが残念だが。","ENG":"Too bad you're using that skill to butcher people.","TWN":"可惜你只會把射擊術用在殺人。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"그 인간백정이 영감님 목숨을 지켜주고 있다는 건 알고 있는지 모르겠네.","JPN":"その殺し屋が今ジジイの命を守ってやってることはわかってんのか？","ENG":"I'll have you know that this butcher here is keeping you alive.","TWN":"你別忘了殺人犯正在保護你這老頭的命。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"그나저나 이대로는 얼마 못 버텨.","JPN":"ところで、このままじゃ長くは持たない。","ENG":"But we're not going to last much longer like this.","TWN":"不過這樣下去撐不了太久。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"놈들이 방패병이라도 불러서 근접전으로 나오면 당장 도망쳐야 해.","JPN":"奴らが盾兵でも呼んで近接戦に持ち込まれたら、すぐ逃げなきゃならねえ。","ENG":"If they bring out their shieldmen to turn this into a melee, we have to bail right away.","TWN":"如果他們叫來盾牌士兵展開近戰，我們得馬上逃跑。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"......젠장, 차라리 방패병이 나을 뻔 했네.","JPN":"……くそ、盾兵のがマシだったな。","ENG":"Dang, I would have preferred the shieldmen.","TWN":"……該死，還不如叫來盾牌士兵。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"갱단 녀석들 주제에 저런 첨단 무기는 어디서 구한 거야?","JPN":"ギャングのくせに、あんな最新兵器をどこで手に入れたんだ？","ENG":"Where the hell did gangsters manage to score cutting-edge weapons like that?","TWN":"這些歹徒從哪裡弄來了那種高科技武器？"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"전투 드론이로군. 저런 걸 전문으로 취급하는 밀매상들이 있다고 들었지.","JPN":"戦闘ドローンだな。ああいうものを専門に取り扱う密売商人がいると聞いた。","ENG":"Combat drones. I heard there were folks specializing in those at the black market.","TWN":"是戰鬥無人機。我聽說有一些黑商專門販賣那些武器。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"영감도 시대 변화를 좀 따라가지 그랬어?","JPN":"ジジイも時代の変化に合わせていけばよかったんじゃないか。","ENG":"Why didn't you keep up with the trend yourself?","TWN":"老頭你也應該與時俱進啊？"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"난 구식 인간이라서 인공지능 같은 건 별로 신뢰하지 않아.","JPN":"ワシは昔の人間だから、人工知能なんか信用できんぞ。","ENG":"I'm too old-fashioned to believe in crap like artificial intelligence.","TWN":"我這種抱殘守缺的老頭可不會相信人工智慧。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"......할 수 없군.","JPN":"……仕方ないな。","ENG":"Oh, well.","TWN":"……沒辦法了。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"살아남으려면 구식 전술을 쓸 수밖에.","JPN":"生き残るためには古い戦術を使うしかない。","ENG":"I guess I'll just have to resort to one of those old-fashioned tactics.","TWN":"為了保命，只能採取老套的戰術。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"뭐? 무슨 짓을 하려고.","JPN":"なんだ？　何をするつもりだ。","ENG":"Huh? What are you going to do?","TWN":"嗯？你想幹什麼？"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"내가 나가서 미끼가 될 거야.","JPN":"ワシが出て、囮になろう。","ENG":"I'll bait them out there.","TWN":"我去當誘餌。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"그러니까 잘 하는 거라곤 총 쏘는 거밖에 없는 네놈이 드론을 쏴서 떨어트려.","JPN":"だから、射撃しかできないお前さんがドローンを撃ち落とせ。","ENG":"Since shooting's the only thing you're good at, shoot down the drones when I'm out there.","TWN":"你這個只會射擊的傢伙負責破壞那個無人機。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"미쳤어? 그 나이 먹고 무슨 자신감이야?","JPN":"正気か？　その歳で囮だって？","ENG":"Are you crazy? You're not exactly in your prime!","TWN":"瘋了？你這老頭哪來的自信？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"관절염 있다고 했던 것 같은데 제대로 달릴 수나 있어?","JPN":"この前関節炎になったとか言ってただろ。走れるのか？","ENG":"Can you even run properly with your arthritis?","TWN":"你不是說患上了關節炎嗎，你還跑得動嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"이래 봬도 이 바닥에서 아직까지 살아남은 몸이다. 노인을 우습게 보지 마.","JPN":"こう見えても、この業界でこの歳になるまで生き残ったワシだ。老いぼれをなめんなよ。","ENG":"I'll have you know this old sack of bones managed to survive this long for a reason, boy.","TWN":"我畢竟在這個世界混了這麼多年，別小看老人。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"젠장...... 알겠어.","JPN":"くそ……わかった。","ENG":"Gah... Okay.","TWN":"該死……知道了。"},"stage":{"bg":"CORRIDOR","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"걱정 말라고. 절대로 죽게 놔두지 않을 테니까.","JPN":"心配すんな。絶対に死なせないから。","ENG":"Don't worry. I won't let you die so easily.","TWN":"放心，我絕對不會讓你送死。"},"stage":{"bg":"CORRIDOR","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"내 총알에는 눈이 달려 있다는 걸 보여 드리지.","JPN":"俺の弾丸には目がついていることを見せてやろうじゃないか。","ENG":"Let me show you how my bullets have eyes of their own.","TWN":"我的子彈是長著眼睛的。"},"stage":{"bg":"CORRIDOR","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL"}]`);export{e as default};